import React from "react";
import Logo from '../../assets//img/logo.png'
import './Menu.css'
import ButtonLink from "./components/ButtonLink";

function Menu(){
    return (
        <nav className="Menu">
            <a href="/">
                <img className="Logo" src={Logo} alt="clovisflix logo"
                 />
            </a>      
            <ButtonLink href="/" className="ButtonLink"/>
            
        </nav>
    );
}

export default Menu;
